content.text:
terraform {
  required_providers {
    azuread = { source = "hashicorp/azuread" }
    azurerm = { source = "hashicorp/azurerm" }
  }
}

resource "azuread_application" "deployer" {
  display_name = "github-deployer"
}

resource "azuread_service_principal" "deployer" {
  client_id = azuread_application.deployer.client_id
}

resource "azuread_application_federated_identity_credential" "github_main" {
  application_id = azuread_application.deployer.id
  display_name   = "github-main-branch"
  description    = "GitHub Actions on main branch"
  audiences      = ["api://AzureADTokenExchange"]
  issuer         = "https://token.actions.githubusercontent.com"
  subject        = "repo:${var.github_org}/${var.github_repo}:ref:refs/heads/main"
}

resource "azuread_application_federated_identity_credential" "github_prod_env" {
  application_id = azuread_application.deployer.id
  display_name   = "github-production-environment"
  audiences      = ["api://AzureADTokenExchange"]
  issuer         = "https://token.actions.githubusercontent.com"
  subject        = "repo:${var.github_org}/${var.github_repo}:environment:production"
}

# Assign Contributor role to the service principal on a resource group
data "azurerm_subscription" "current" {}

resource "azurerm_role_assignment" "deployer_contributor" {
  scope                = "/subscriptions/${data.azurerm_subscription.current.subscription_id}/resourceGroups/${var.resource_group}"
  role_definition_name = "Contributor"
  principal_id         = azuread_service_principal.deployer.object_id
}

output "client_id" {
  value = azuread_application.deployer.client_id
}
